172: 	/**
173: 	 * A reunion of the two ranges.
174: 	 * The smallest position will be used as the start point, and the largest one as the end point.
175: 	 */
176: 	public plusRange(range: IRange): Range {
177: 		return Range.plusRange(this, range);
178: 	}
179: 
180: 	/**
181: 	 * A reunion of the two ranges.
182: 	 * The smallest position will be used as the start point, and the largest one as the end point.
183: 	 */
184: 	public static plusRange(a: IRange, b: IRange): Range {
185: 		let startLineNumber: number;
186: 		let startColumn: number;
187: 		let endLineNumber: number;
188: 		let endColumn: number;
189: 
190: 		if (b.startLineNumber < a.startLineNumber) {
191: 			startLineNumber = b.startLineNumber;
192: 			startColumn = b.startColumn;
193: 		} else if (b.startLineNumber === a.startLineNumber) {
194: 			startLineNumber = b.startLineNumber;
195: 			startColumn = Math.min(b.startColumn, a.startColumn);
196: 		} else {
197: 			startLineNumber = a.startLineNumber;
198: 			startColumn = a.startColumn;
199: 		}
200: 
201: 		if (b.endLineNumber > a.endLineNumber) {
202: 			endLineNumber = b.endLineNumber;
203: 			endColumn = b.endColumn;
204: 		} else if (b.endLineNumber === a.endLineNumber) {
205: 			endLineNumber = b.endLineNumber;
206: 			endColumn = Math.max(b.endColumn, a.endColumn);
207: 		} else {
208: 			endLineNumber = a.endLineNumber;
209: 			endColumn = a.endColumn;
210: 		}
211: 
212: 		return new Range(startLineNumber, startColumn, endLineNumber, endColumn);
213: 	}
