494: export class Searcher {
495: 	public readonly _wordSeparators: WordCharacterClassifier | null;
496: 	private readonly _searchRegex: RegExp;
497: 	private _prevMatchStartIndex: number;
498: 	private _prevMatchLength: number;
499: 
500: 	constructor(wordSeparators: WordCharacterClassifier | null, searchRegex: RegExp,) {
501: 		this._wordSeparators = wordSeparators;
502: 		this._searchRegex = searchRegex;
503: 		this._prevMatchStartIndex = -1;
504: 		this._prevMatchLength = 0;
505: 	}
506: 
507: 	public reset(lastIndex: number): void {
508: 		this._searchRegex.lastIndex = lastIndex;
509: 		this._prevMatchStartIndex = -1;
510: 		this._prevMatchLength = 0;
511: 	}
512: 
513: 	public next(text: string): RegExpExecArray | null {
514: 		const textLength = text.length;
515: 
516: 		let m: RegExpExecArray | null;
517: 		do {
518: 			if (this._prevMatchStartIndex + this._prevMatchLength === textLength) {
519: 				// Reached the end of the line
520: 				return null;
521: 			}
522: 
523: 			m = this._searchRegex.exec(text);
524: 			if (!m) {
525: 				return null;
526: 			}
527: 
528: 			const matchStartIndex = m.index;
529: 			const matchLength = m[0].length;
530: 			if (matchStartIndex === this._prevMatchStartIndex && matchLength === this._prevMatchLength) {
531: 				if (matchLength === 0) {
532: 					// the search result is an empty string and won't advance `regex.lastIndex`, so `regex.exec` will stuck here
533: 					// we attempt to recover from that by advancing by two if surrogate pair found and by one otherwise
534: 					if (strings.getNextCodePoint(text, textLength, this._searchRegex.lastIndex) > 0xFFFF) {
535: 						this._searchRegex.lastIndex += 2;
536: 					} else {
537: 						this._searchRegex.lastIndex += 1;
538: 					}
539: 					continue;
540: 				}
541: 				// Exit early if the regex matches the same range twice
542: 				return null;
543: 			}
544: 			this._prevMatchStartIndex = matchStartIndex;
545: 			this._prevMatchLength = matchLength;
546: 
547: 			if (!this._wordSeparators || isValidMatch(this._wordSeparators, text, textLength, matchStartIndex, matchLength)) {
548: 				return m;
549: 			}
550: 
551: 		} while (m);
552: 
553: 		return null;
554: 	}
555: }
