218: function isBuiltinSelector(selector: LanguageSelector): boolean {
219: 	if (typeof selector === 'string') {
220: 		return false;
221: 	}
222: 
223: 	if (Array.isArray(selector)) {
224: 		return selector.some(isBuiltinSelector);
225: 	}
226: 
227: 	return Boolean((selector as LanguageFilter).isBuiltin);
228: }
