431: function leftIsWordBounday(wordSeparators: WordCharacterClassifier, text: string, textLength: number, matchStartIndex: number, matchLength: number): boolean {
432: 	if (matchStartIndex === 0) {
433: 		// Match starts at start of string
434: 		return true;
435: 	}
436: 
437: 	const charBefore = text.charCodeAt(matchStartIndex - 1);
438: 	if (wordSeparators.get(charBefore) !== WordCharacterClass.Regular) {
439: 		// The character before the match is a word separator
440: 		return true;
441: 	}
442: 
443: 	if (charBefore === CharCode.CarriageReturn || charBefore === CharCode.LineFeed) {
444: 		// The character before the match is line break or carriage return.
445: 		return true;
446: 	}
447: 
448: 	if (matchLength > 0) {
449: 		const firstCharInMatch = text.charCodeAt(matchStartIndex);
450: 		if (wordSeparators.get(firstCharInMatch) !== WordCharacterClass.Regular) {
451: 			// The first character inside the match is a word separator
452: 			return true;
453: 		}
454: 	}
455: 
456: 	return false;
457: }
458: 
459: function rightIsWordBounday(wordSeparators: WordCharacterClassifier, text: string, textLength: number, matchStartIndex: number, matchLength: number): boolean {
460: 	if (matchStartIndex + matchLength === textLength) {
461: 		// Match ends at end of string
462: 		return true;
463: 	}
464: 
465: 	const charAfter = text.charCodeAt(matchStartIndex + matchLength);
466: 	if (wordSeparators.get(charAfter) !== WordCharacterClass.Regular) {
467: 		// The character after the match is a word separator
468: 		return true;
469: 	}
470: 
471: 	if (charAfter === CharCode.CarriageReturn || charAfter === CharCode.LineFeed) {
472: 		// The character after the match is line break or carriage return.
473: 		return true;
474: 	}
475: 
476: 	if (matchLength > 0) {
477: 		const lastCharInMatch = text.charCodeAt(matchStartIndex + matchLength - 1);
478: 		if (wordSeparators.get(lastCharInMatch) !== WordCharacterClass.Regular) {
479: 			// The last character in the match is a word separator
480: 			return true;
481: 		}
482: 	}
483: 
484: 	return false;
485: }
