69: export function isMultilineRegexSource(searchString: string): boolean {
70: 	if (!searchString || searchString.length === 0) {
71: 		return false;
72: 	}
73: 
74: 	for (let i = 0, len = searchString.length; i < len; i++) {
75: 		const chCode = searchString.charCodeAt(i);
76: 
77: 		if (chCode === CharCode.LineFeed) {
78: 			return true;
79: 		}
80: 
81: 		if (chCode === CharCode.Backslash) {
82: 
83: 			// move to next char
84: 			i++;
85: 
86: 			if (i >= len) {
87: 				// string ends with a \
88: 				break;
89: 			}
90: 
91: 			const nextChCode = searchString.charCodeAt(i);
92: 			if (nextChCode === CharCode.n || nextChCode === CharCode.r || nextChCode === CharCode.W) {
93: 				return true;
94: 			}
95: 		}
96: 	}
97: 
98: 	return false;
99: }
