29: 	public parseSearchRequest(): SearchData | null {
30: 		if (this.searchString === '') {
31: 			return null;
32: 		}
33: 
34: 		// Try to create a RegExp out of the params
35: 		let multiline: boolean;
36: 		if (this.isRegex) {
37: 			multiline = isMultilineRegexSource(this.searchString);
38: 		} else {
39: 			multiline = (this.searchString.indexOf('\n') >= 0);
40: 		}
41: 
42: 		let regex: RegExp | null = null;
43: 		try {
44: 			regex = strings.createRegExp(this.searchString, this.isRegex, {
45: 				matchCase: this.matchCase,
46: 				wholeWord: false,
47: 				multiline: multiline,
48: 				global: true,
49: 				unicode: true
50: 			});
51: 		} catch (err) {
52: 			return null;
53: 		}
