59: 		let canUseSimpleSearch = (!this.isRegex && !multiline);
60: 		if (canUseSimpleSearch && this.searchString.toLowerCase() !== this.searchString.toUpperCase()) {
61: 			// casing might make a difference
62: 			canUseSimpleSearch = this.matchCase;
63: 		}
