114: 	private readonly _lineFeedsOffsets: number[];
115: 
116: 	constructor(text: string) {
117: 		const lineFeedsOffsets: number[] = [];
118: 		let lineFeedsOffsetsLen = 0;
119: 		for (let i = 0, textLen = text.length; i < textLen; i++) {
120: 			if (text.charCodeAt(i) === CharCode.LineFeed) {
121: 				lineFeedsOffsets[lineFeedsOffsetsLen++] = i;
122: 			}
123: 		}
124: 		this._lineFeedsOffsets = lineFeedsOffsets;
125: 	}
126: 
127: 	public findLineFeedCountBeforeOffset(offset: number): number {
128: 		const lineFeedsOffsets = this._lineFeedsOffsets;
129: 		let min = 0;
130: 		let max = lineFeedsOffsets.length - 1;
131: 
132: 		if (max === -1) {
133: 			// no line feeds
134: 			return 0;
135: 		}
136: 
137: 		if (offset <= lineFeedsOffsets[0]) {
138: 			// before first line feed
139: 			return 0;
140: 		}
141: 
142: 		while (min < max) {
143: 			const mid = min + ((max - min) / 2 >> 0);
144: 
145: 			if (lineFeedsOffsets[mid] >= offset) {
146: 				max = mid - 1;
147: 			} else {
148: 				if (lineFeedsOffsets[mid + 1] >= offset) {
149: 					// bingo!
150: 					min = mid;
151: 					max = mid;
152: 				} else {
153: 					min = mid + 1;
154: 				}
155: 			}
156: 		}
157: 		return min + 1;
158: 	}
159: }
