192: 			const lineFeedCountInMatch = lineFeedCountBeforeEndOfMatch - lineFeedCountBeforeMatch;
193: 			endOffset = startOffset + match0.length + lineFeedCountInMatch /* add as many \r as there were \n */;
194: 		} else {
