73: 		if (!a && !b) {
74: 			return true;
75: 		}
76: 		return (
77: 			!!a &&
78: 			!!b &&
79: 			a.lineNumber === b.lineNumber &&
80: 			a.column === b.column
81: 		);
82: 	}
