116: 	 * If the two positions are equal, the result will be true.
117: 	 */
118: 	public static isBeforeOrEqual(a: IPosition, b: IPosition): boolean {
119: 		if (a.lineNumber < b.lineNumber) {
120: 			return true;
121: 		}
122: 		if (b.lineNumber < a.lineNumber) {
123: 			return false;
