156: 
157: 		const notebookInfo = this._notebookInfoResolver?.(model.uri);
158: 
159: 		// use the uri (scheme, pattern) of the notebook info iff we have one
160: 		// otherwise it's the model's/document's uri
161: 		const candidate = notebookInfo
162: 			? new MatchCandidate(model.uri, model.getLanguageId(), notebookInfo.uri, notebookInfo.type, recursive)
163: 			: new MatchCandidate(model.uri, model.getLanguageId(), undefined, undefined, recursive);
164: 
165: 		if (this._lastCandidate?.equals(candidate)) {
166: 			// nothing has changed
167: 			return;
