321: export function replaceAsync(str: string, search: RegExp, replacer: (match: string, ...args: any[]) => Promise<string>): Promise<string> {
322: 	const parts: (string | Promise<string>)[] = [];
323: 
324: 	let last = 0;
325: 	for (const match of str.matchAll(search)) {
326: 		parts.push(str.slice(last, match.index));
327: 		if (match.index === undefined) {
328: 			throw new Error('match.index should be defined');
329: 		}
330: 
331: 		last = match.index + match[0].length;
332: 		parts.push(replacer(match[0], ...match.slice(1), match.index, str, match.groups));
333: 	}
334: 
335: 	parts.push(str.slice(last));
336: 
337: 	return Promise.all(parts).then(p => p.join(''));
