439: 	public static compareRangesUsingStarts(a: IRange | null | undefined, b: IRange | null | undefined): number {
440: 		if (a && b) {
441: 			const aStartLineNumber = a.startLineNumber | 0;
442: 			const bStartLineNumber = b.startLineNumber | 0;
443: 
444: 			if (aStartLineNumber === bStartLineNumber) {
445: 				const aStartColumn = a.startColumn | 0;
446: 				const bStartColumn = b.startColumn | 0;
