747: /**
748:  * Given a string and a max length returns a shorted version. Shorting
749:  * happens at favorable positions - such as whitespace or punctuation characters.
750:  * The return value can be longer than the given value of `n`. Leading whitespace is always trimmed.
751:  */
752: export function lcut(text: string, n: number, prefix = '') {
753: 	const trimmed = text.trimStart();
754: 
755: 	if (trimmed.length < n) {
756: 		return trimmed;
757: 	}
758: 
759: 	const re = /\b/g;
760: 	let i = 0;
761: 	while (re.test(trimmed)) {
762: 		if (trimmed.length - re.lastIndex < n) {
763: 			break;
764: 		}
765: 
766: 		i = re.lastIndex;
767: 		re.lastIndex += 1;
768: 	}
769: 
770: 	if (i === 0) {
771: 		return trimmed;
772: 	}
773: 
774: 	return prefix + trimmed.substring(i).trimStart();
775: }
