782: export function* forAnsiStringParts(str: string) {
783: 	let last = 0;
784: 	for (const match of str.matchAll(CSI_SEQUENCE)) {
785: 		if (last !== match.index) {
786: 			yield { isCode: false, str: str.substring(last, match.index) };
787: 		}
788: 
789: 		yield { isCode: true, str: match[0] };
790: 		last = match.index + match[0].length;
791: 	}
792: 
793: 	if (last !== str.length) {
794: 		yield { isCode: false, str: str.substring(last) };
795: 	}
