{"content":"194: 	private static _compareByScoreAndTime(a: Entry<any>, b: Entry<any>): number {
195: 		if (a._score < b._score) {
196: 			return 1;
197: 		} else if (a._score > b._score) {
198: 			return -1;
199: 		}
200: 
201: 		// De-prioritize built-in providers
202: 		if (isBuiltinSelector(a.selector) && !isBuiltinSelector(b.selector)) {
203: 			return 1;
204: 		} else if (!isBuiltinSelector(a.selector) && isBuiltinSelector(b.selector)) {
205: 			return -1;
206: 		}
207: 
208: 		if (a._time < b._time) {
209: 			return 1;
210: 		} else if (a._time > b._time) {
211: 			return -1;
212: 		} else {
213: 			return 0;
214: 		}
215: 	}
216: }
